end
plot(EnvPars.best_tx_cal(pos_probe), EnvPars.best_ty_cal(pos_probe), ... %[output:63f5421b]
     'rx', 'MarkerSize', 16, 'LineWidth', 2.5); %[output:63f5421b]
xlim([0.5, T_x+0.5]); ylim([0.5, T_y+0.5]); %[output:63f5421b]
xlabel('$t_x$', 'Interpreter','latex'); %[output:63f5421b]
ylabel('$t_y$', 'Interpreter','latex'); %[output:63f5421b]
title(sprintf('Optimal policy $\\pi^\\star$ at pos %d | $\\psi_x$=%.2f rad', ... %[output:63f5421b]
