title(sprintf('$Q^\\star$ at start $(t_x=%d, t_y=%d)$ | pos %d', ... %[output:9cde73c2]
              tx_start, ty_start, pos_probe), 'Interpreter','latex'); %[output:9cde73c2]
[~, best_a] = max(Q_at_start);
xline(best_a, 'r--', 'LineWidth', 2, 'Label', '$\pi^\star$', ... %[output:9cde73c2]
      'Interpreter', 'latex'); %[output:9cde73c2]
grid on; set(gca,'FontSize',12); %[output:9cde73c2]

%% Plot 4 — Simulate optimal policy from random starts, measure steps to peak
N_sim         = 100;
steps_to_peak = zeros(N_cal, N_sim);

for pos = 1:N_cal
    for sim = 1:N_sim
        tx = randi(T_x);
        ty = randi(T_y);

        for k = 1:EnvPars.MaxStepsPerEpisode
            a       = policy(pos, tx, ty);
            tx_next = mod(tx - 1 + EnvPars.delta_moves(a,1), T_x) + 1;
            ty_next = mod(ty - 1 + EnvPars.delta_moves(a,2), T_y) + 1;

            if tx_next == EnvPars.best_tx_cal(pos) && ...
               ty_next == EnvPars.best_ty_cal(pos)
                steps_to_peak(pos, sim) = k;
                break;
            end
            tx = tx_next;
            ty = ty_next;
        end
    end
end

figure; %[output:566da2d4]
histogram(steps_to_peak(steps_to_peak > 0), ... %[output:566da2d4]
          'BinWidth', 1, 'FaceColor', [0.2 0.5 0.8], 'Normalization','probability'); %[output:566da2d4]
xlabel('Steps to reach peak',    'Interpreter','latex'); %[output:566da2d4]
ylabel('Fraction of episodes',   'Interpreter','latex'); %[output:566da2d4]
title('Steps needed by $\pi^\star$ from random starts', 'Interpreter','latex'); %[output:566da2d4]
xline(mean(steps_to_peak(steps_to_peak>0)), 'r--', 'LineWidth', 2, ... %[output:566da2d4]
      'Label', 'mean', 'Interpreter','latex'); %[output:566da2d4]
grid on; set(gca,'FontSize',12); %[output:566da2d4]

%% Summary
reached     = steps_to_peak(steps_to_peak > 0);
not_reached = sum(steps_to_peak(:) == 0);
fprintf('=== Optimal policy simulation (%d starts × %d positions) ===\n', N_sim, N_cal); %[output:05acabbc]
fprintf('Mean steps to peak   : %.2f\n',  mean(reached)); %[output:4ab0cadc]
fprintf('Max  steps to peak   : %d\n',    max(reached)); %[output:0f782545]
fprintf('Never reached peak   : %.1f%%n', 100*not_reached/(N_cal*N_sim)); %[output:89f2334a]
fprintf('Within MaxSteps (%d) : %.1f%%n', EnvPars.MaxStepsPerEpisode, ... %[output:group:0c6a159d] %[output:8a0d78cd]
        100*mean(reached <= EnvPars.MaxStepsPerEpisode)); %[output:group:0c6a159d] %[output:8a0d78cd]
fprintf('=========================================================\n'); %[output:70d8c4c2]
%%
%[text] ### Random Way Point mobility model
% Parameters
t = 0:delta_time:time_simul;     % time vector in s

EnvPars.tolerance = pi/25;
%% Initialization
Nsteps = length(t);
pos_MU_traj = zeros(3, Nsteps);

% Initial position
pos_MU_init=[1 2 1.5];
current_pos = pos_MU_init(:);
current_pos(1) = min(max(current_pos(1), 0), L_hall);
current_pos(2) = min(max(current_pos(2), 0), W_hall);

pos_MU_traj(:,1) = current_pos;

% Initial mobility state
state = "move";   % either "move" or "pause"

% First target waypoint
target_pos = [L_hall*rand; W_hall*rand; current_pos(3)];

% Pause handling
pause_end_time = -inf;

%% Time evolution
for k = 2:Nsteps
    
    dt = t(k) - t(k-1);
    
    % In case of non-positive time step, keep previous position
    if dt <= 0
        pos_MU_traj(:,k) = pos_MU_traj(:,k-1);
        continue;
    end
    
    if state == "move"
        
        % Vector toward target
        dvec = target_pos(1:2) - current_pos(1:2);
        dist_to_target = norm(dvec);
        travel_dist = MU_speed * dt;
        
        if dist_to_target <= travel_dist
            % Reach waypoint within this time step
            current_pos(1:2) = target_pos(1:2);
            
            % Switch to pause state
            pause_duration = pause_min + (pause_max - pause_min)*rand;
            pause_end_time = t(k) + pause_duration;
            state = "pause";
            
        else
            % Move toward waypoint
            direction = dvec / dist_to_target;
            current_pos(1:2) = current_pos(1:2) + direction * travel_dist;
        end
        
    elseif state == "pause"
        
        % Stay still during pause
        if t(k) >= pause_end_time
            % Pause finished, choose new waypoint and move again
            target_pos = [L_hall*rand; W_hall*rand; current_pos(3)];
            state = "move";
        end
        
    end
    
    % Store position
    pos_MU_traj(:,k) = current_pos;
end

% Enforce constant z-coordinate
pos_MU_traj(3,:) = pos_MU_init(3);

%[text] #### Including the channel coherence time
%[text] **Description**:In this block we include the number of transmittions along wich the channel is coherent.This is similar to assuming the user keeps the same position.
% pos_MU_traj = repelem(pos_MU_traj, 1, floor(N_packets_coh*delta_time/T_coh));
pos_MU_traj = repelem(pos_MU_traj, 1, 5);
