x_ticks = 0 : pi/2 : 2*pi;
y_ticks = 0 : pi/2 : 2*pi;
x_tick_labels = arrayfun(@localPiTickLabel, x_ticks, 'UniformOutput', false);
y_tick_labels = arrayfun(@localPiTickLabel, y_ticks, 'UniformOutput', false);

figure;

% --- Subplot A: trivial preset ---
